                            {section.label}
                          </h2>
                        </div>
                        <div className="h-px w-20 bg-[#072D42]/60 mx-auto"></div>
                      </div>
                    </Reveal>

                    {/* NUEVAS TARJETAS - MÁXIMO 3 POR FILA EN DESKTOP */}
                    <div className="flex justify-center">
                      <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-8 w-full max-w-7xl">
                        {teamMembers[section.id].map((member, memberIndex) => (
                          <Reveal key={member.id} delay={(index * 100) + (memberIndex * 100)}>
                            <div className="bg-white rounded-2xl shadow-xl border border-[#072D42]/10 hover:shadow-2xl hover:border-[#072D42]/20 transition-all duration-500 ease-out group overflow-hidden h-full flex flex-col">
                              <div className="flex-1 p-6">
                                <div className="flex items-start gap-4 mb-4">
                                  {/* Avatar */}
                                  <div className="flex-shrink-0">
