                                    <h3 className="font-playfair text-xl text-[#072D42] group-hover:text-[#0A3A5A] font-normal mb-1 transition-colors duration-300 truncate">
                                      {member.name}
                                    </h3>
                                    <p className="font-inter text-[#072D42]/80 text-base mb-2 font-medium">
                                      {member.position}
                                    </p>
                                    
                                    {/* Información adicional */}
                                    <div className="space-y-1 mb-3">
                                      <div className="flex items-center gap-2 text-sm text-[#072D42]/70">
                                        <Calendar className="w-3 h-3" />
                                        <span>{member.experience}</span>
                                      </div>
                                      <div className="flex items-center gap-2 text-sm text-[#072D42]/70">
                                        <MapPin className="w-3 h-3" />
                                        <span className="truncate">{member.location}</span>
                                      </div>
                                      <div className="flex items-center gap-2 text-sm text-[#072D42]/70">
                                        <Mail className="w-3 h-3" />
                                        <span className="truncate">{member.email}</span>
                                      </div>
                                    </div>
                                  </div>
                                </div>
                                
                                {/* Skills */}
                                <div className="flex flex-wrap gap-2">
                                  {member.skills.map((skill, skillIndex) => (
