                                    </span>
                                  ))}
                                </div>
                              </div>
                              
                              {/* Icono de la sección en la parte inferior */}
                              <div className="border-t border-[#072D42]/5 bg-gradient-to-br from-gray-50 to-white group-hover:from-gray-100 group-hover:to-gray-50 transition-all duration-500 p-4 flex items-center justify-center">
